import { mkdir, mkdtemp, readFile, rm, writeFile } from "node:fs/promises";
import { tmpdir } from "node:os";
import path from "node:path";
import { fileURLToPath } from "node:url";
import { build } from "tsdown";

const scriptDirectory = path.dirname(fileURLToPath(import.meta.url));
const clientRoot = path.resolve(scriptDirectory, "..");
const coreRoot = path.resolve(clientRoot, "..", "core");
const coreClientTypesEntry = path.join(coreRoot, "src", "types", "client.ts");
const coreTsconfigPath = path.join(coreRoot, "tsconfig.json");
const generatedDirectory = path.join(clientRoot, "src", "generated");
const generatedFile = path.join(generatedDirectory, "core-client-types.ts");

/**
 * Removes declaration sourcemap comments so the vendored file stays standalone.
 */
const stripSourceMapComment = (content) =>
	content.replace(/^\s*\/\/# sourceMappingURL=.*$/gm, "").trim();

/**
 * Rewrites declaration imports to type-only imports so the generated TypeScript emits no runtime dependency code.
 */
const rewriteDeclarationImports = (content) =>
	content.replace(/^import\s+(?!type\b)/gm, "import type ");

/**
 * Rewrites declaration re-exports so TypeScript treats the generated bundle as type-only.
 */
const rewriteDeclarationExports = (content) =>
	content.replace(/^export\s+\{/gm, "export type {");

/**
 * Builds the core client types and copies the bundled declaration into client.
 */
const generateClientTypes = async () => {
	const temporaryOutDirectory = await mkdtemp(
		path.join(tmpdir(), "lucid-client-types-"),
	);

	try {
		await build({
			config: false,
			cwd: coreRoot,
			entry: {
				"core-client-types": coreClientTypesEntry,
			},
			tsconfig: coreTsconfigPath,
			outDir: temporaryOutDirectory,
			format: "esm",
			unbundle: false,
			dts: {
				emitDtsOnly: true,
				sourcemap: false,
			},
			sourcemap: false,
			clean: true,
			shims: false,
			platform: "node",
		});

		const bundledTypes = await readFile(
			path.join(temporaryOutDirectory, "core-client-types.d.mts"),
			"utf8",
		);

		const fileContents = [
			"// This file is auto-generated by `npm run generate:client-types`.",
			"// Do not edit manually.",
			"",
			rewriteDeclarationExports(
				rewriteDeclarationImports(stripSourceMapComment(bundledTypes)),
			),
			"",
		].join("\n");

		await mkdir(generatedDirectory, { recursive: true });
		await writeFile(generatedFile, fileContents);

		console.log(
			`Generated ${path.relative(clientRoot, generatedFile)} from core client types.`,
		);
	} finally {
		await rm(temporaryOutDirectory, { recursive: true, force: true });
	}
};

await generateClientTypes();
